import React from 'react';
import './p1.css';
// import Greet from "./navd.js";

import nature from "./assets/nature.jpg"


function App() {
  return (
    <>
      <h1>Let's Learn React!</h1>
      {/* <Greet /> */}

      <img src={nature} 
      alt="Nature image" style={{width: "300px",borderRadius: "10px"}}/>

    <table className="container" border="1">

      <thead>
        <tr>
          <th>Days</th>
          <th>Sunday</th>
          <th>Monday</th>
          <th>Tuesday</th>
          <th>Thursday</th>
          <th>Friday</th>
          <th>Saturday</th>
        </tr>
      </thead>

      <tbody>
        <tr>
          <td>Working Hours</td>
          <td>9-5</td>
          <td>9-5</td>
          <td>9-5</td>
          <td>9-5</td>
          <td>9-5</td>
          <td>9-5</td>
        </tr>
      </tbody>

    </table>
    </>

  );
}

export default App;
